// Helper for timeval subtraction if not defined in header (inline implementation)
void tvsub(struct timeval *tout, struct timeval *tin, struct timeval *tout_res) {
    tout_res->tv_sec = tout->tv_sec - tin->tv_sec;
    tout_res->tv_usec = tout->tv_usec - tin->tv_usec;
    if (tout_res->tv_usec < 0) {
        tout_res->tv_sec--;
        tout_res->tv_usec += 1000000;
    }
}
